import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { orderAPI } from '../services/orderAPI';
import { customerAPI } from '../services/customerAPI';
import Sidebar from '../components/Sidebar';

const OrdersPage = () => {
  const { token } = useAuth();
  const [orders, setOrders] = useState([]);
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [error, setError] = useState(null);
  const [formData, setFormData] = useState({
    customer_id: '',
    order_id_external: '',
    amount: '',
    order_date: '',
    product_category: '',
  });

  useEffect(() => {
    fetchOrders();
    fetchCustomers();
  }, []);

  const fetchOrders = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await orderAPI.getAll(token);
      setOrders(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchCustomers = async () => {
    try {
      const data = await customerAPI.getAll(token);
      setCustomers(data);
    } catch (err) {
      console.error('Error fetching customers:', err);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);

    try {
      if (editingId) {
        await orderAPI.update(editingId, formData, token);
      } else {
        await orderAPI.create(formData, token);
      }
      setFormData({
        customer_id: '',
        order_id_external: '',
        amount: '',
        order_date: '',
        product_category: '',
      });
      setEditingId(null);
      setShowForm(false);
      fetchOrders();
    } catch (err) {
      setError(err.message);
    }
  };

  const handleEdit = (order) => {
    setFormData({
      customer_id: order.customer_id,
      order_id_external: order.order_id_external,
      amount: order.amount,
      order_date: order.order_date.split('T')[0],
      product_category: order.product_category,
    });
    setEditingId(order.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure?')) {
      try {
        await orderAPI.delete(id, token);
        fetchOrders();
      } catch (err) {
        setError(err.message);
      }
    }
  };

  const handleCancel = () => {
    setFormData({
      customer_id: '',
      order_id_external: '',
      amount: '',
      order_date: '',
      product_category: '',
    });
    setEditingId(null);
    setShowForm(false);
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white flex">
      <Sidebar active="/orders" />
      <div className="flex-1">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-3xl font-bold">Orders</h1>
          <button
            onClick={() => setShowForm(!showForm)}
            className="bg-blue-600 hover:bg-blue-700 px-6 py-2 rounded transition"
          >
            {showForm ? 'Cancel' : 'Add Order'}
          </button>
        </div>

        {error && (
          <div className="mb-4 p-4 bg-red-900 text-red-100 rounded">
            {error}
          </div>
        )}

        {showForm && (
          <div className="bg-gray-800 rounded-lg p-6 mb-8">
            <h2 className="text-xl font-bold mb-4">
              {editingId ? 'Edit Order' : 'Add New Order'}
            </h2>
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <select
                name="customer_id"
                value={formData.customer_id}
                onChange={handleInputChange}
                className="bg-gray-700 px-4 py-2 rounded text-white"
                required
              >
                <option value="">Select Customer</option>
                {customers.map((customer) => (
                  <option key={customer.id} value={customer.id}>
                    {customer.name}
                  </option>
                ))}
              </select>
              <input
                type="text"
                name="order_id_external"
                placeholder="Order ID"
                value={formData.order_id_external}
                onChange={handleInputChange}
                className="bg-gray-700 px-4 py-2 rounded text-white"
                required
                disabled={!!editingId}
              />
              <input
                type="number"
                name="amount"
                placeholder="Amount"
                value={formData.amount}
                onChange={handleInputChange}
                className="bg-gray-700 px-4 py-2 rounded text-white"
                step="0.01"
                required
              />
              <input
                type="date"
                name="order_date"
                value={formData.order_date}
                onChange={handleInputChange}
                className="bg-gray-700 px-4 py-2 rounded text-white"
                required
              />
              <input
                type="text"
                name="product_category"
                placeholder="Product Category"
                value={formData.product_category}
                onChange={handleInputChange}
                className="bg-gray-700 px-4 py-2 rounded text-white"
              />
              <div className="flex gap-2">
                <button
                  type="submit"
                  className="flex-1 bg-green-600 hover:bg-green-700 px-4 py-2 rounded transition"
                >
                  {editingId ? 'Update' : 'Add'} Order
                </button>
                <button
                  type="button"
                  onClick={handleCancel}
                  className="flex-1 bg-gray-600 hover:bg-gray-700 px-4 py-2 rounded transition"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        )}

        {loading ? (
          <div className="text-center py-8">Loading...</div>
        ) : orders.length === 0 ? (
          <div className="text-center py-8 text-gray-400">No orders yet</div>
        ) : (
          <div className="bg-gray-800 rounded-lg overflow-hidden">
            <table className="w-full">
              <thead className="bg-gray-700">
                <tr>
                  <th className="px-6 py-3 text-left">Order ID</th>
                  <th className="px-6 py-3 text-left">Customer</th>
                  <th className="px-6 py-3 text-left">Amount</th>
                  <th className="px-6 py-3 text-left">Category</th>
                  <th className="px-6 py-3 text-left">Date</th>
                  <th className="px-6 py-3 text-left">Actions</th>
                </tr>
              </thead>
              <tbody>
                {orders.map((order) => (
                  <tr key={order.id} className="border-t border-gray-700 hover:bg-gray-750">
                    <td className="px-6 py-3">{order.order_id_external}</td>
                    <td className="px-6 py-3">{order.customer_name}</td>
                    <td className="px-6 py-3">₹{order.amount.toFixed(2)}</td>
                    <td className="px-6 py-3">{order.product_category || '-'}</td>
                    <td className="px-6 py-3">{new Date(order.order_date).toLocaleDateString()}</td>
                    <td className="px-6 py-3 space-x-2">
                      <button
                        onClick={() => handleEdit(order)}
                        className="bg-blue-600 hover:bg-blue-700 px-3 py-1 rounded text-sm"
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => handleDelete(order.id)}
                        className="bg-red-600 hover:bg-red-700 px-3 py-1 rounded text-sm"
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default OrdersPage;
